//! Emits the GNAT project file (`azul.gpr`) that wraps the generated
//! `azul.ads` / `azul.adb` and links against the prebuilt native library.
//!
//! The user is expected to drop the platform-appropriate native binary
//! (`libazul.so` / `libazul.dylib` / `azul.dll`) in the project root,
//! and `gprbuild -P azul.gpr` will compile and link.

/// Single deterministic GPR string.
pub fn generate_gpr() -> String {
    let s = r#"-- ============================================================================
-- Auto-generated GNAT project file for the Azul GUI framework Ada bindings.
-- Generated by azul-doc codegen v2 (lang_ada/gpr). DO NOT EDIT MANUALLY.
-- ============================================================================
--
-- Build with:
--     gprbuild -P azul.gpr
--
-- Place libazul.so / libazul.dylib / azul.dll alongside this file.

library project Azul is

   for Languages use ("Ada");
   for Source_Dirs use (".");
   for Object_Dir use "obj";
   for Library_Name use "azul_bindings";
   for Library_Dir use "lib";
   for Library_Kind use "static";

   package Compiler is
      for Default_Switches ("Ada") use ("-gnat2012", "-gnatwa", "-gnatyM120");
   end Compiler;

   package Linker is
      -- Resolve to libazul.so / libazul.dylib / azul.dll on each platform.
      for Linker_Options use ("-L.", "-lazul");
   end Linker;

end Azul;
"#;
    s.to_string()
}
